using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
            Assert.Equal(3, list.Count);
        }

        [Fact]
        public void Constructor_SinglePage_SetsTotalPagesTo1()
        {
            var items = new List<string> { "a", "b" };

            var list = new PaginatedList<string>(items, 2, 1, 10);

            Assert.Equal(1, list.PageIndex);
            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);

            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);

            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);

            Assert.False(list.HasNextPage); // TotalPages = 2, PageIndex = 2
        }

        [Fact]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);

            Assert.True(list.HasNextPage); // TotalPages = 2, PageIndex = 1
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(10, result.Count);
            Assert.Equal(11, result.First());
            Assert.Equal(20, result.Last());
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(3, result.PageIndex);
            Assert.Equal(5, result.Count);
            Assert.Equal(21, result.First());
            Assert.Equal(25, result.Last());
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3, 4, 5 };

            var list = new PaginatedList<int>(items, 20, 1, 5);

            Assert.Equal(5, list.Count);
            Assert.Contains(1, list);
            Assert.Contains(5, list);
        }
    }
}

using System;
using Xunit;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from the static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            _service.SendNotification("Course", "42", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCreateMessage()
        {
            _service.SendNotification("Student", "1", "Jane", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.StartsWith("New Student 'Jane' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesUpdateMessage()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            _service.SendNotification("Department", "5", "Math", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Department 'Math' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            var before = DateTime.Now.AddSeconds(-1);

            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var after = DateTime.Now.AddSeconds(1);
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();

            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_MultipleMessages_ReturnsInFIFOOrder()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            var n1 = _service.ReceiveNotification();
            var n2 = _service.ReceiveNotification();
            var n3 = _service.ReceiveNotification();
            var n4 = _service.ReceiveNotification();

            Assert.Equal("A", n1.EntityType);
            Assert.Equal("B", n2.EntityType);
            Assert.Equal("C", n3.EntityType);
            Assert.Null(n4);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op but should not throw
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_NullDisplayName_UsesEntityId()
        {
            _service.SendNotification("Student", "99", null, EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 99", notification.Message);
        }

        [Fact]
        public void SendNotification_EmptyDisplayName_UsesEntityId()
        {
            _service.SendNotification("Student", "99", "", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 99", notification.Message);
        }

        [Fact]
        public void SendNotification_WhitespaceDisplayName_UsesEntityId()
        {
            _service.SendNotification("Student", "99", "   ", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 99", notification.Message);
        }
    }
}

using System;
using System.ComponentModel.DataAnnotations;
using System.Collections.Generic;
using System.Linq;
using Xunit;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        private IList<ValidationResult> ValidateModel(object model)
        {
            var results = new List<ValidationResult>();
            var context = new ValidationContext(model, null, null);
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }

        // Person / Student / Instructor FullName
        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Today
            };

            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void Instructor_FullName_ReturnsLastNameCommaFirstName()
        {
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = DateTime.Today
            };

            Assert.Equal("Doe, Jane", instructor.FullName);
        }

        // ErrorViewModel
        [Fact]
        public void ErrorViewModel_ShowRequestId_TrueWhenRequestIdSet()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenRequestIdNull()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenRequestIdEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }

        // Student validation
        [Fact]
        public void Student_Valid_PassesValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);

            Assert.Empty(results);
        }

        [Fact]
        public void Student_MissingLastName_FailsValidation()
        {
            var student = new Student
            {
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_MissingFirstName_FailsValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_LastNameTooLong_FailsValidation()
        {
            var student = new Student
            {
                LastName = new string('A', 51),
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstNameTooLong_FailsValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = new string('A', 51),
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        // Course validation
        [Fact]
        public void Course_Valid_PassesValidation()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Empty(results);
        }

        [Fact]
        public void Course_TitleTooShort_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_CreditsOutOfRange_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 6,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_NegativeCredits_FailsValidation()
        {
            var course = new Course
