{"file_text": "using System;
using System.ComponentModel.DataAnnotations;
using System.Collections.Generic;
using System.Linq;
using Xunit;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        private IList<ValidationResult> ValidateModel(object model)
        {
            var results = new List<ValidationResult>();
            var context = new ValidationContext(model, null, null);
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }

        // Person / Student / Instructor FullName
        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Today
            };

            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void Instructor_FullName_ReturnsLastNameCommaFirstName()
        {
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = DateTime.Today
            };

            Assert.Equal("Doe, Jane", instructor.FullName);
        }

        // ErrorViewModel
        [Fact]
        public void ErrorViewModel_ShowRequestId_TrueWhenRequestIdSet()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenRequestIdNull()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenRequestIdEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }

        // Student validation
        [Fact]
        public void Student_Valid_PassesValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);

            Assert.Empty(results);
        }

        [Fact]
        public void Student_MissingLastName_FailsValidation()
        {
            var student = new Student
            {
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_MissingFirstName_FailsValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_LastNameTooLong_FailsValidation()
        {
            var student = new Student
            {
                LastName = new string('A', 51),
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstNameTooLong_FailsValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = new string('A', 51),
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var results = ValidateModel(student);

            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        // Course validation
        [Fact]
        public void Course_Valid_PassesValidation()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Empty(results);
        }

        [Fact]
        public void Course_TitleTooShort_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_CreditsOutOfRange_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 6,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_NegativeCredits_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = -1,
                DepartmentID = 1
            };

            var results = ValidateModel(course);

            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        // Department validation
        [Fact]
        public void Department_NameTooShort_FailsValidation()
        {
            var department = new Department
            {
                Name = "AB",
                Budget = 100000,
                StartDate = DateTime.Today
            };

            var results = ValidateModel(department);

            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        // Notification validation
        [Fact]
        public void Notification_Valid_PassesValidation()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = DateTime.Now
            };

            var results = ValidateModel(notification);

            Assert.Empty(results);
        }

        [Fact]
        public void Notification_MissingEntityType_FailsValidation()
        {
            var notification = new Notification
            {
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = DateTime.Now
            };

            var results = ValidateModel(notification);

            Assert.Contains(results, r => r.MemberNames.Contains("EntityType"));
        }

        // Enrollment
        [Fact]
        public void Enrollment_GradeCanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1,
                StudentID = 1,
                Grade = null
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_GradeValues_AreCorrect()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }

        // OfficeAssignment
        [Fact]
        public void OfficeAssignment_LocationTooLong_FailsValidation()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = new string('A', 51)
            };

            var results = ValidateModel(oa);

            Assert.Contains(results, r => r.MemberNames.Contains("Location"));
        }

        // View models
        [Fact]
        public void AssignedCourseData_Properties_Work()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1,
                Title = "Test",
                Assigned = true
            };

            Assert.Equal(1, data.CourseID);
            Assert.Equal("Test", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void InstructorIndexData_Properties_Work()
        {
            var data = new InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.Empty(data.Instructors);
            Assert.Empty(data.Courses);
            Assert.Empty(data.Enrollments);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties_Work()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = DateTime.Parse("2020-09-01"),
                StudentCount = 5
            };

            Assert.Equal(DateTime.Parse("2020-09-01"), group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_NullDate_IsAllowed()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = null,
                StudentCount = 0
            };

            Assert.Null(group.EnrollmentDate);
        }

        // EntityOperation enum
        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }
    }
}
