using System;
using System.Linq;
using System.Net;
using Xunit;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedDatabase(_context);
            _controller = new StudentsController(_context);
            TestHelpers.SetupControllerContext(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // ===== INDEX =====

        [Fact]
        public void Index_DefaultSort_ReturnsStudentsOrderedByLastName()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(3, model.Count);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_NameDescSort_ReturnsStudentsDescending()
        {
            var result = _controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Anand", model.First().LastName);
        }

        [Fact]
        public void Index_DateSort_ReturnsStudentsOrderedByDate()
        {
            var result = _controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
            // Earliest enrollment date first
            Assert.Equal("Alexander", model.First().LastName); // 2010
        }

        [Fact]
        public void Index_DateDescSort_ReturnsStudentsOrderedByDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Anand", model.First().LastName); // 2013
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
