using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Net;
using System.Text;
using Xunit;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedDatabase(_context);
            _envMock = new Mock<IWebHostEnvironment>();
            _loggerMock = new Mock<ILogger<CoursesController>>();

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
            TestHelpers.SetupControllerContext(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        private IFormFile CreateMockFile(string fileName, string content, long? overrideLength = null)
        {
            var bytes = Encoding.UTF8.GetBytes(content);
            var stream = new MemoryStream(bytes);
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(overrideLength ?? bytes.Length);
            fileMock.Setup(f => f.OpenReadStream()).Returns(stream);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => stream.CopyTo(s));
            return fileMock.Object;
        }

        // ===== INDEX =====

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        // ===== DETAILS =====

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var course = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        // ===== CREATE (GET) =====

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // ===== CREATE (POST) =====

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Contains(_context.Courses, c => c.CourseID == 9999);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 9999, DepartmentID = 1 };

            var result = _controller.Create(course, null);

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesImageAndCourse()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = 1
            };
            var file = CreateMockFile("test.jpg", "fake image content");

            var result = _controller.Create(course, file);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);

            var savedCourse = _context.Courses.Find(8888);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 7777,
                Title = "Bad Image",
                Credits = 3,
                DepartmentID = 1
            };
            var file = CreateMockFile("test.exe", "malicious content");

            var result = _controller.Create(course, file);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_WithOversizedFile_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "Big Image",
                Credits = 3,
                DepartmentID = 1
            };
            var file = CreateMockFile("big.jpg", "x", overrideLength: 6 * 1024 * 1024);

            var result = _controller.Create(course, file);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // ===== EDIT (GET) =====

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit((int?)1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var course = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", course.Title);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit((int?)9999);

            Assert.IsType<NotFoundResult>(result);
        }

        // ===== EDIT (POST) =====

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedCourse = new Course
            {
                CourseID = 1050,
                Title = "Chemistry Updated",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Edit(updatedCourse, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, DepartmentID = 1 };

            var result = _controller.Edit(course, null);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Post_WithValidImage_UpdatesImagePath()
        {
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedCourse = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var file = CreateMockFile("new_image.png", "new image data");

            var result = _controller.Edit(updatedCourse, file);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_WithInvalidImageExtension_ReturnsError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var file = CreateMockFile("hack.txt", "text content");

            var result = _controller.Edit(course, file);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_WithOversizedImage_ReturnsError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var file = CreateMockFile("big.png", "x", overrideLength: 10 * 1024 * 1024);

            var result = _controller.Edit(course, file);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // ===== DELETE (GET) =====

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var course = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        // ===== DELETE (POST) =====

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            var countBefore = _context.Courses.Count();

            var result = _controller.DeleteConfirmed(1050);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(countBefore - 1, _context.Courses.Count());
        }

        [Fact]
        public void DeleteConfirmed_CourseWithImage_DeletesImageFile()
        {
            // Create an image file
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var imageFile = Path.Combine(uploadsDir, "test_image.jpg");
            File.WriteAllText(imageFile, "fake image");

            // Set image path on course
            var course = _context.Courses.Find(1050);
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(1050);

            Assert.False(File.Exists(imageFile));
        }

        [Fact]
        public void Create_Post_AllowedImageExtensions_AreAccepted()
        {
            var extensions = new[] { ".jpg", ".jpeg", ".png", ".gif", ".bmp" };
            int courseId = 5000;

            foreach (var ext in extensions)
            {
                var course = new Course
                {
                    CourseID = courseId++,
                    Title = $"Course{ext}",
                    Credits = 3,
                    DepartmentID = 1
                };
                var file = CreateMockFile($"image{ext}", "content");

                var result = _controller.Create(course, file);

                Assert.IsType<RedirectToActionResult>(result);
            }
        }
    }
}

