using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using Xunit;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedDatabase(_context);
            _controller = new InstructorsController(_context);
            TestHelpers.SetupControllerContext(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // ===== INDEX =====

        [Fact]
        public void Index_NoSelection_ReturnsAllInstructors()
        {
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorSelected_ReturnsCourses()
        {
            var result = _controller.Index(1, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.NotEmpty(model.Courses);
            Assert.Equal(1, _controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            var instructors = model.Instructors.ToList();
            Assert.Equal("Abercrombie", instructors[0].LastName);
            Assert.Equal("Fakhouri", instructors[1].LastName);
        }

        // ===== DETAILS =====

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var instructor = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        // ===== CREATE (GET) =====

        [Fact]
        public void Create_Get_ReturnsViewWithAssignedCourses()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var instructor = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // ===== CREATE (POST) =====

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Teacher",
                HireDate = DateTime.Parse("2020-01-15")
            };

            var result = _controller.Create(instructor, null);

